        check(test, 1972, 6, 9);

        copy = test.year().addToCopy(-1972);
        check(copy, 0, 6, 9);

        copy = test.year().addToCopy(-1973);
        check(copy, -1, 6, 9);

        try {
            test.year().addToCopy(-292275054 - 1972 - 1);
            fail();
        } catch (IllegalArgumentException ex) {}
        check(test, 1972, 6, 9);
    }

